// // This module compares two 4-bit numbers and returns true if the first number is less than or equal to the second number when mode is 0, and vice versa.
module top_module(
    input [3:0] A,
    input [3:0] B,
    input mode,
    output result
);assign result = (mode == 0) ? (A > B) : (A < B);

endmodule
